import React, { useState } from 'react';

export default function AudioExtractor() {
  const [url, setUrl] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);

  const handleDownload = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!url) return;

    setLoading(true);

    try {
      const response = await fetch('http://localhost:5000/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (!response.ok) throw new Error('Network response failed');

      const blob = await response.blob();
      const downloadUrl = window.URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = downloadUrl;
      link.setAttribute('download', 'extracted-audio.mp3'); 

      document.body.appendChild(link);
      link.click();
      link.remove();

      window.URL.revokeObjectURL(downloadUrl);
      setUrl(''); // Clear input on success
    } catch (error) {
      console.error("Error downloading file:", error);
      alert("Failed to extract audio. Please check the URL.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <div style={styles.header}>
          <div style={styles.iconWrapper}>🎵</div>
          <h1 style={styles.title}>Audio Extractor</h1>
          <p style={styles.subtitle}>Convert your favorite videos to high-quality MP3 tracks instantly</p>
        </div>

        <form onSubmit={handleDownload} style={styles.form}>
          <div style={styles.inputContainer}>
            <input 
              type="text" 
              value={url} 
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => setUrl(e.target.value)} 
              placeholder="Paste video or audio link here..." 
              disabled={loading}
              style={{
                ...styles.input,
                ...(loading ? styles.inputDisabled : {})
              }}
            />
          </div>

          <button 
            type="submit" 
            disabled={loading || !url.trim()} 
            style={{
              ...styles.button,
              ...(loading ? styles.buttonLoading : {}),
              ...(!url.trim() && !loading ? styles.buttonDisabled : {})
            }}
          >
            {loading ? (
              <div style={styles.loaderContainer}>
                <span style={styles.spinner}></span>
                <span>Extracting Audio...</span>
              </div>
            ) : (
              'Download MP3'
            )}
          </button>
        </form>
      </div>
    </div>
  );
}

